import { useState, useEffect } from "react";
import { useSelector } from "react-redux";
import { useParams, useNavigate } from "react-router-dom";
import { toast } from "react-toastify";

function TakeTest() {
  const { testId } = useParams();
  const user = useSelector((state) => state.auth.user);
  const navigate = useNavigate();
  const [test, setTest] = useState(null);
  const [answers, setAnswers] = useState([]);

  useEffect(() => {
    fetch(`http://localhost:3001/tests/${testId}`)
      .then((res) => res.json())
      .then((data) => {
        setTest(data);
        setAnswers(new Array(data.questions.length).fill(null));
      })
      .catch((error) => toast.error("Ошибка загрузки теста"));
  }, [testId]);

  const handleAnswerChange = (questionIndex, answerIndex) => {
    const newAnswers = [...answers];
    newAnswers[questionIndex] = answerIndex;
    setAnswers(newAnswers);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (answers.some((answer) => answer === null)) {
      toast.error("Ответьте на все вопросы!");
      return;
    }

    const correctAnswers = test.questions.map((q) => q.correctAnswerIndex);
    const score = (answers.reduce((acc, answer, index) => {
      return acc + (answer === correctAnswers[index] ? 1 : 0);
    }, 0) / answers.length) * 100;

    const result = {
      userId: user.id,
      testId: parseInt(testId),
      answers,
      score,
      submittedAt: new Date().toISOString(),
    };

    const response = await fetch("http://localhost:3001/test_results", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(result),
    });

    if (response.ok) {
      await fetch("http://localhost:3001/notifications", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          userId: user.id,
          message: `Вы сдали тест "${test.title}" с результатом ${score.toFixed(2)}%.`,
          createdAt: new Date().toISOString(),
        }),
      });
      toast.success("Тест успешно сдан!");
      navigate("/courses");
    } else {
      toast.error("Не удалось сохранить результат теста");
    }
  };

  if (!test) return <div className="container mt-5"><h2>Загрузка...</h2></div>;

  return (
    <div className="container mt-5">
      <h1 className="text-center mb-4">Тест: {test.title}</h1>
      <div className="card shadow">
        <div className="card-body">
          <form onSubmit={handleSubmit}>
            {test.questions.map((question, qIndex) => (
              <div key={question.id} className="mb-4">
                <h5>{qIndex + 1}. {question.text}</h5>
                {question.options.map((option, oIndex) => (
                  <div key={oIndex} className="form-check">
                    <input
                      className="form-check-input"
                      type="radio"
                      name={`question-${qIndex}`}
                      id={`question-${qIndex}-option-${oIndex}`}
                      value={oIndex}
                      checked={answers[qIndex] === oIndex}
                      onChange={() => handleAnswerChange(qIndex, oIndex)}
                    />
                    <label className="form-check-label" htmlFor={`question-${qIndex}-option-${oIndex}`}>
                      {option}
                    </label>
                  </div>
                ))}
              </div>
            ))}
            <button type="submit" className="btn btn-primary w-100">Отправить</button>
          </form>
        </div>
      </div>
    </div>
  );
}

export default TakeTest;
